\section{Análise das Distratores}

\begin{itemize}

\item \textbf{Alternativa A}:
\begin{itemize}
  \item\textit{Raciocínio provável}: Considera a tarifa fixa como um coeficiente multiplicando a variável $F$, confundindo constante com variável.
  \item\textit{Tipo de equívoco}: Interpretação incorreta entre variável e constante.
  \item\textit{Por que parece correta}: Inclui todas as variáveis do problema.
  \item\textit{Por que está errada}: A tarifa fixa é um valor somado, não multiplicado por uma variável.
\end{itemize}

\item \textbf{Alternativa C}:
\begin{itemize}
  \item\textit{Raciocínio provável}: Ignora o coeficiente multiplicador da distância.
  \item\textit{Tipo de equívoco}: Omissão do coeficiente.
  \item\textit{Por que parece correta}: Inclui tarifa fixa e tempo, mas desconsidera custo por distância.
  \item\textit{Por que está errada}: Subestima o custo por não multiplicar a distância por R$1,40.
\end{itemize}

\item \textbf{Alternativa D}:
\begin{itemize}
  \item\textit{Raciocínio provável}: Esquece da tarifa fixa, considerando só os custos variáveis.
  \item\textit{Tipo de equívoco}: Omissão da tarifa fixa.
  \item\textit{Por que parece correta}: Parece razoável pagar apenas pelo tempo e distância.
  \item\textit{Por que está errada}: Tarifa fixa é obrigatória e não está incluída.
\end{itemize}

\item \textbf{Alternativa E}:
\begin{itemize}
  \item\textit{Raciocínio provável}: Usa somente variáveis sem coeficientes numéricos.
  \item\textit{Tipo de equívoco}: Incorreta representação algébrica.
  \item\textit{Por que parece correta}: Parece usar diretamente as variáveis do problema.
  \item\textit{Por que está errada}: Não considera valores monetários, inviabilizando a fórmula.
\end{itemize}

\end{itemize}

